#include <stdio.h>
#include <string.h>
#define MAX 500

int main() {
    int T;
    if (scanf("%d", &T) != 1) return 0;
    while (T--) {
        char expr[MAX];
        scanf("%s", expr);
        char out[MAX];
        int outIdx = 0;
        char stack[MAX];
        int top = -1;
        for (int i = 0; expr[i] != '\0'; ++i) {
            char c = expr[i];
            if (c >= 'a' && c <= 'z') {
                out[outIdx++] = c;
            } else if (c == '(') {
                stack[++top] = c;
            } else if (c == ')') {
                while (top >= 0 && stack[top] != '(') {
                    out[outIdx++] = stack[top--];
                }
                if (top >= 0 && stack[top] == '(') top--; // discard '('
            } else { // operator
                stack[++top] = c;
            }
        }
        while (top >= 0) out[outIdx++] = stack[top--];
        out[outIdx] = '\0';
        printf("%s\n", out);
    }
    return 0;
}

