import sys

def infix_to_postfix(expr: str) -> str:
    out = []
    stack = []
    for ch in expr:
        if 'a' <= ch <= 'z':
            out.append(ch)
        elif ch == '(':
            stack.append(ch)
        elif ch == ')':
            while stack and stack[-1] != '(':
                out.append(stack.pop())
            if stack and stack[-1] == '(':
                stack.pop()
        else:  # operator
            stack.append(ch)
    while stack:
        out.append(stack.pop())
    return ''.join(out)

def main():
    data = sys.stdin.read().strip().splitlines()
    if not data:
        return
    T = int(data[0])
    for i in range(1, T + 1):
        expr = data[i].strip()
        print(infix_to_postfix(expr))

if __name__ == "__main__":
    main()

